scwin.f_selectTabMenu = function (idx) {
  switch (idx) {
    case 0:
      //Main tab
      scwin.tabIndex = 0;
      break;
    case 1:
      //Other tab
      scwin.tabIndex = 1;
      //-------------------------------------------------------------------------------
      //  Door Order 자동 생성 , 신규가 아닐경우에만 적용
      //-------------------------------------------------------------------------------
      if (ds_containerDoorOrder.getRowCount() == 0) {
        scwin.f_autoCreateDoorOrderInfo();
      }
      break;
  }
  tab1.setSelectedTabIndex(idx);
};
scwin.f_autoCreateDoorOrderInfo = function () {
  //한행추가
  ds_containerDoorOrder.reform();
  let idx = ds_containerDoorOrder.insertRow();
  //ds_containerBookingCont에 기본값 설정
  ds_containerDoorOrder.setCellData(idx, "kcomcd", hd_kcomcd.getValue());
  ds_containerDoorOrder.setCellData(idx, "bkNo", ed_bkNo.getValue());
  ds_containerDoorOrder.setCellData(idx, "doordt", scwin.strCurDate + scwin.currentTime); //ORDER DATE
  ds_containerDoorOrder.setCellData(idx, "bkdoorseq", "01"); //ORDER SEQ
  ds_containerDoorOrder.setCellData(idx, "internalTyp", "2"); //1:내부부서,2:거래처
  ds_containerDoorOrder.setCellData(idx, "transcd", "109856"); //운송사 CODE
  ds_containerDoorOrder.setCellData(idx, "inpid", scwin.userId);
  ds_containerDoorOrderQty.reform();
  let idx2 = ds_containerDoorOrderQty.insertRow();
  //ds_containerDoorOrderQty에 기본값 설정
  ds_containerDoorOrderQty.setCellData(idx2, "kcomcd", hd_kcomcd.getValue());
  ds_containerDoorOrderQty.setCellData(idx2, "bkNo", ed_bkNo.getValue());
  ds_containerDoorOrderQty.setCellData(idx2, "bkdoorseq", "01"); //ORDER SEQ
  ds_containerDoorOrderQty.setCellData(idx2, "qty", "0");
  if (lc_cfs.getValue() == "F") {
    ds_containerDoorOrderQty.setCellData(idx2, "qtytype", "22GP"); //CONTAINER TYPE OR LCL
  } else if (lc_cfs.getValue() == "L") {
    ds_containerDoorOrderQty.setCellData(idx2, "qtytype", "R/T"); //CONTAINER TYPE OR LCL
  }
  scwin.f_doorTypeQtyLoading(idx2, "qtytype"); //qty 변경
  ds_containerDoorOrderQty.setCellData(idx2, "inpid", scwin.userId);
};
scwin.f_RetrieveBinding = function (ds, gubun) {
  switch (gubun) {
    case "RetrieveBookingHbl":
      ds.set("kcomcd", hd_kcomcd.getValue());
      ds.set("hblno", "");
      ds.set("inpid", scwin.userId);
      break;
  } //end switch
};
scwin.f_Retrieve = async function () {
  if (cnd_ed_bkNo.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_056, new Array("Booking No")); // 선택된 @이(가) 없습니다.
    return;
  } else {
    dma_retrieve.setEmptyValue();
    dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
    dma_retrieve.set("bkNo", cnd_ed_bkNo.getValue());
    await $c.sbm.execute($p, sbm_retrieve);
    if (ds_containerBookingList.getRowCount() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); //  해당되는 자료가 존재하지 않습니다
      scwin.f_Set("INIT");
      scwin.f_Check();
    } else {
      ds_containerBookingList.setRowPosition(0);
      let v_totPkg = 0;
      let v_totWgt = 0;
      let v_totMsr = 0;
      for (let i = 0; i < ds_containerBookingCont.getRowCount(); i++) {
        v_totPkg += +ds_containerBookingCont.getCellData(i, "cntpkg");
        v_totWgt += +ds_containerBookingCont.getCellData(i, "cntwgt");
        v_totMsr += +ds_containerBookingCont.getCellData(i, "cntmsrt");
      }
      ed_totpkg.setValue(v_totPkg.toString());
      ed_totwgt.setValue(v_totWgt.toString());
      ed_totmsr.setValue(v_totMsr.toString());
      scwin.f_Set("RETRIEVE");
      gr_containerDoorOrder.setFocusedCell(0, 0);
      if (ds_containerBookingList.getCellData(0, "contractno") != "") {
        let v_contractno = ds_containerBookingList.getCellData(0, "contractno");
        if (v_contractno == "NONE") {
          await scwin.f_ContractInfo(); // 이걸하니까 됨.
          ds_ctrtNo.removeAll();
          let row = ds_ctrtNo.insertRow();
          ds_ctrtNo.setCellData(row, "ctrtNo", "NONE");
          lc_contractno.setValue("NONE");
        } else {
          await scwin.f_ContractInfo();
        }
      }
    }
    cnd_ed_bkNo.focus();
  }
  scwin.f_containerGridTypeLoading();
};
scwin.f_FieldClear = async function () {
  cnd_ed_bkNo.setValue("");
};
scwin.f_Create = async function () {
  scwin.f_Set("CREATE");
  cnd_ed_bkNo.setValue("");
  ds_containerBookingList.removeAll();
  ds_containerBookingList.reform();
  let row = ds_containerBookingList.insertRow();

  // dataset clear
  ds_containerDoorOrder.removeAll();
  ds_containerDoorOrderQty.removeAll();
  ds_containerBookingCont.removeAll();
  ds_houseblList.removeAll();
  ds_containerBookingList.setRowPosition(row);
  scwin.f_Check();
  tab1.setSelectedTabIndex(0); // 1번째 탭으로 이동.
  ed_reDt.setValue(scwin.strCurDate);

  // ed_bkPic.setValue(scwin.userId);//asis는 값이 제대로 들어가지 않는듯
  ed_bkPicNm.setValue(scwin.userNm);
  ed_wgt.setValue("0");
  ed_msr.setValue("0");
  ed_cntqty1.setValue("0");
  ed_cntqty2.setValue("0");
  ed_cntqty3.setValue("0");
  ed_cntqty4.setValue("0");
  scwin.f_containerGridTypeLoading();
  //2019.04.08 최우성 대리 요청사항: 해상수입 부킹 시 CUSTOMER CODE 에 자동으로 999908 ( 공통거래처(국제)) 입력
  ed_custCd.setValue("999908");
  ed_custNm.setValue("공통거래처(국제)");
  scwin.f_PopUp('Customer', 'T');

  // 2020.02.26 국제영업3팀 개선사항 Department 기본 설정
  if (!$c.util.isEmpty($p, scwin.vLobranCd)) {
    ed_dept.setValue(scwin.vLobranCd);
    ed_deptnm.setValue(scwin.vLobranNm);
  }
  await scwin.f_ContractInfo();
};
scwin.f_Update = async function () {
  //bulk booking 마감 여부.
  if (ds_containerBookingList.getCellData(0, "cfs") == "B") {
    let param1 = hd_kcomcd.getValue();
    let param2 = cnd_ed_bkNo.getValue();
    dma_bkCloseCheck.set("sysCd", "SeaImportBookingEBC");
    dma_bkCloseCheck.set("queryId", "retrivebkCloseCheck");
    dma_bkCloseCheck.set("param1", param1);
    dma_bkCloseCheck.set("param2", param2);
    await $c.sbm.execute($p, sbm_bkCloseCheck);
    if (ds_bkCloseCheck.getCellData(0, "CODE") == "Y") {
      await $c.win.alert($p, "Bring to a close");
      return;
    }
  }
  if (ed_bkNo.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["HEADER"]); // @은(는) 필수 입력 항목입니다.
    return;
  } else {
    $c.gus.cfDisableObjects($p, [btn_Clear]);
    scwin.f_Set("UPDATE");
  }
};
scwin.f_Save = async function () {
  if (!ds_containerBookingList.getModifiedIndex().length && !ds_containerDoorOrder.getModifiedIndex().length && !ds_containerDoorOrderQty.getModifiedIndex().length && !ds_containerBookingCont.getModifiedIndex().length) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["Container Booking"]); //@은(는) 변경된 사항이 없습니다
    return;
  }
  if (!(await scwin.f_validate()) || !(await $c.win.confirm($p, E_MSG_CM_CRM_001))) {
    //저장하시겠습니까?
    return;
  }
  debugger;
  if (ed_bkPic.getValue() == "" && ed_docPic.getValue() == "") {
    await $c.win.alert($p, "Booking담당자/Doc담당자 중 한 가지는 필수로 입력하여야 합니다.");
    return;
  }
  if (ed_bkNo.getValue() == "") {
    // BOOKING NO 를 생성및 가져온다.
    dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
    dma_retrieve.set("bkEta", ed_bkEta.getValue()); // 다른 dataset정보를  	dma_retrieve dataset에 넣음.
    dma_retrieve.set("cfs", lc_cfs.getValue()); // 다른 dataset정보를  	dma_retrieve dataset에 넣음.
    await $c.sbm.execute($p, sbm_retrievebookingNo);
    ed_bkNo.setValue(ds_retrieveNo.getCellData(ds_retrieveNo.getRowPosition() || 0, "bkNo"));
  }

  // OC_BK_HBL 에 HBLNO CHECK
  dma_retrieve.set("kcomcd", hd_kcomcd.getValue());
  dma_retrieve.set("bkNo", ed_bkNo.getValue());
  dma_retrieve.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition() || 0, "bkdoorseq"));
  await $c.sbm.execute($p, sbm_retrievebookingHbl);

  // OC_BK_HBL 의 HBLNO 가 NULL이 아닐때  ALERT
  if (ds_bookingHbl.getCellData(0, "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
    // 저장
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "kcomcd", hd_kcomcd.getValue());
    if (lc_cfs.getValue() == "B") {
      // Bulk
      ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkbltype", "B");
    } else {
      ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkbltype", hd_bkbltype.getValue());
    }
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "bkEta", ed_bkEta.getValue());
    ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition() || 0, "inpid", scwin.userId);

    //-------------------------------------------------------------------------------
    //  Door Order 자동 생성
    //-------------------------------------------------------------------------------
    if (ds_containerDoorOrder.getRowCount() == 0) {
      scwin.f_autoCreateDoorOrderInfo();
    } else {
      //신규로 작성한 건이 아니거나 Door Order 탭을 먼저 선택하여 행이 이미 만들어진경우 bkNo만 다시 설정
      ds_containerDoorOrderQty.setCellData(ds_containerDoorOrderQty.getRowPosition() || 0, "bkNo", ed_bkNo.getValue());
      ds_containerDoorOrder.setCellData(ds_containerDoorOrder.getRowPosition() || 0, "bkNo", ed_bkNo.getValue());
    }
    await $c.sbm.execute($p, sbm_save);
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001); //  성공적으로 저장하였습니다.
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["House B/L"]); // 이미 존재하는 @입니다.
  }
  scwin.f_Set("SAVE");
  cnd_ed_bkNo.setValue(ed_bkNo.getValue());
  await scwin.f_Retrieve();
};
scwin.undoAll = function (dltObj) {
  // dltObj.setBroadcast(false);
  for (let idx = dltObj.getRowCount() - 1; idx >= 0; --idx) {
    if (dltObj.getRowStatus(idx) == "C") {
      dltObj.removeRow(idx);
    } else {
      dltObj.undoRow(idx);
    }
  }
  // dltObj.setBroadcast(true, true);
};
scwin.f_Cancel = function () {
  if (scwin.statusFlag == "C") {
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
    scwin.undoAll(ds_containerBookingList);
    scwin.undoAll(ds_ctrtNo);
    scwin.f_cancelRow(1);
    scwin.f_cancelRow(2);
    scwin.f_cancelRow(3);
    cnd_ed_bkNo.focus();
    scwin.processFlag = "T";
  }
};
