scwin.f_containerDualCheck = async function () {
  let v_containerCheck = true;
  if (ed_cnttype1.getValue() != "" && ed_cnttype2.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype2.getValue()) {
    v_containerCheck = false;
  } else if (ed_cnttype1.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype3.getValue()) {
    v_containerCheck = false;
  } else if (ed_cnttype1.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype4.getValue()) {
    v_containerCheck = false;
  } else if (ed_cnttype2.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype3.getValue()) {
    v_containerCheck = false;
  } else if (ed_cnttype2.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype4.getValue()) {
    v_containerCheck = false;
  } else if (ed_cnttype3.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype3.getValue() == ed_cnttype4.getValue()) {
    v_containerCheck = false;
  }
  if (!v_containerCheck) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_032, Array("Container Type")); //  @은(는) 중복될 수 없습니다.
  }
  return v_containerCheck;
};
