scwin.gr_houseblList_oncelldblclick = function (row, columnIndex, columnId) {
  let menuNm = "Import House B/L";
  let src = "/ui/il/seainb/sibl/se_201_01_01b.xml";
  let menuId = "se_201_01_01b.jsp";
  let paramObj = {
    linkcheck: "1",
    kcomcd: hd_kcomcd.getValue(),
    mhno: ds_houseblList.getCellData(row, "mhno")
  };
  if (ds_houseblList.getCellData(row, "autono") == "DIRECT" && ds_houseblList.getCellData(row, "hhbltype") == "B") {
    //Bulk
    //개발대상에서 제외된 화면이라 막음
    return;
    src = "/ui/il/seainb/sibl/se_203_01_01b.xml";
    menuId = "se_203_01_01b";
    menuNm = "Import Bulk B/L";
  } else {
    //House
    paramObj.blno = ds_houseblList.getCellData(row, "hhblno");
  }
  $c.win.openMenu($p, menuNm, src, menuId, paramObj, {
    openAction: "exist"
  });
};
scwin.gr_containerDoorOrder_onviewchange = async function (info) {
  if (info.colId == "bkdoorseq") {
    let value = info.newValue;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
      if (i == info.rowIndex) {
        continue;
      }
      if (value == ds_containerDoorOrder.getCellData(i, "bkdoorseq")) {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_032, Array("Container Seq")); //  @은(는) 중복될 수 없습니다.
        gr_containerDoorOrder.setFocusedCell(info.rowIndex, "bkdoorseq", true);
        return;
      }
    }
  }
};
scwin.gr_containerDoorOrder_ontextimageclick = function (row, columnIndex) {
  let colId = gr_containerDoorOrder.getColumnID(columnIndex);
  switch (colId) {
    case "transcd":
      if (ds_containerDoorOrder.getCellData(row, "internalTyp") == "1") {
        scwin.f_PopUpGrid("Department", row, "F");
      } else {
        scwin.f_PopUpGrid("Customer", row, "F");
      }
      break;
    case "fcity":
      scwin.f_PopUpGrid("PickupCy", row, "F");
      break;
    case "doorcd":
      scwin.f_PopUpGrid("Door", row, "F");
      break;
    case "tcity":
      scwin.f_PopUpGrid("GateinCy", row, "F");
      break;
  }
};
scwin.gr_containerDoorOrder_onafteredit = function (row, columnIndex, value) {
  let colId = gr_containerDoorOrder.getColumnID(columnIndex);
  switch (colId) {
    case "transcd":
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
        if (ds_containerDoorOrder.getCellData(row, "internalTyp") == "1") {
          ds_containerDoorOrder.setCellData(row, "transnm", "");
          scwin.f_PopUpGrid("Department", row, "T");
        } else {
          ds_containerDoorOrder.setCellData(row, "transnm", "");
          scwin.f_PopUpGrid("Customer", row, "T");
        }
        //Name field 존재시 check.
        //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
        ds_containerDoorOrder.setCellData(row, "transcd", "");
        ds_containerDoorOrder.setCellData(row, "transnm", "");
      }
      break;
    case "fcity":
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
        ds_containerDoorOrder.setCellData(row, "fcitynm", "");
        scwin.f_PopUpGrid("PickupCy", row, "T");
        //Name field 존재시 check.
        //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
        ds_containerDoorOrder.setCellData(row, "fcity", "");
        ds_containerDoorOrder.setCellData(row, "fcitynm", "");
      }
      break;
    case "doorcd":
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
        ds_containerDoorOrder.setCellData(row, "doornm", "");
        scwin.f_PopUpGrid("Door", row, "T");
        //Name field 존재시 check.
        //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
        ds_containerDoorOrder.setCellData(row, "doorcd", "");
        ds_containerDoorOrder.setCellData(row, "doornm", "");
      }
      break;
    case "tcity":
      //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
      if (ds_containerDoorOrder.getCellData(row, colId).trim() != "") {
        ds_containerDoorOrder.setCellData(row, "tcitynm", "");
        scwin.f_PopUpGrid("GateinCy", row, "T");
        //Name field 존재시 check.
        //Name Value 가 Blank 일경우 코드값을 Blank 한다.
      } else if (ds_containerDoorOrder.getCellData(row, colId).trim() == "") {
        ds_containerDoorOrder.setCellData(row, "tcity", "");
        ds_containerDoorOrder.setCellData(row, "tcitynm", "");
      }
      break;
    default:
      break;
  }
};
