scwin.ds_containerDoorOrder_onrowpositionchange = async function (info) {
  let row = info.newRowIndex;
  if (row < 0 || row === null) {
    return;
  }
  let v_kcomcd = ds_containerDoorOrder.getCellData(row, "kcomcd");
  let v_bkdoorseq = ds_containerDoorOrder.getCellData(row, "bkdoorseq");
  let v_bkNo = ds_containerDoorOrder.getCellData(row, "bkNo");
  v_kcomcd = v_kcomcd == "" ? "DBEX" : v_kcomcd;
  if (ds_containerDoorOrder.getRowStatus(row) != "C") {
    dma_containerDoorOrderQty.set("bkdoorseq", v_bkdoorseq);
    dma_containerDoorOrderQty.set("bkNo", v_bkNo);
    dma_containerDoorOrderQty.set("kcomcd", v_kcomcd);
    await $c.sbm.execute($p, sbm_retrieveOrder);
    let v_totPkg = 0;
    let v_totWgt = 0;
    let v_totMsr = 0;
    for (let i = 0; i < ds_containerBookingCont.getRowCount(); i++) {
      v_totPkg += +ds_containerBookingCont.getCellData(i, "cntpkg");
      v_totWgt += +ds_containerBookingCont.getCellData(i, "cntwgt");
      v_totMsr += +ds_containerBookingCont.getCellData(i, "cntmsrt");
    }
    ed_totpkg.setValue(v_totPkg.toString());
    ed_totwgt.setValue(v_totWgt.toString());
    ed_totmsr.setValue(v_totMsr.toString());
    if (ds_containerDoorOrderQty.getRowCount()) {
      gr_containerDoorOrderQty.setFocusedCell(0, "bkdoorseq", false);
      gr_containerDoorOrder.setFocusedCell(gr_containerDoorOrder.getFocusedRowIndex(), gr_containerDoorOrder.getFocusedColumnIndex() ?? 1, false);
    }
  } else if (ds_containerDoorOrder.getRowStatus(row) == "C") {
    if (ds_containerDoorOrder.getModifiedJSON().length != 0) {
      ds_containerDoorOrderQty.removeAll();
    }
  }
};
